const body = $input.first().json.body;

function findIKUrls(obj, urls = new Set()) {
  if (typeof obj === 'string') {
    if (obj.includes('ik.imagekit.io')) {
      const normalized = obj.split('?')[0].replace(/^\/\//, 'https://');
      urls.add(normalized);
    }
  } else if (Array.isArray(obj)) {
    obj.forEach(item => findIKUrls(item, urls));
  } else if (obj && typeof obj === 'object') {
    Object.values(obj).forEach(val => findIKUrls(val, urls));
  }
  return urls;
}

const urls = [...findIKUrls(body)];

return urls.map(url => ({ json: { url } }));

const urls = $('Extract ImageKit URLs').all();

const items = $input.all().map((item, index) => ({
  url: urls.at(index).json.url,
  requestId: item.json.requestId,
  status: 'pending'
}));

return items.map(item => ({ json: item }));

